export interface SelectionRange {
    start: number;
    end: number;
}

export interface DomPosition {
    node: Node;
    offset: number;
}

export interface CaretVisualPosition {
    rect: DOMRect;
    offset: number;
}

function getTextNodes(root: HTMLElement): Text[] {
    const walker = document.createTreeWalker(
        root,
        NodeFilter.SHOW_TEXT
    );

    const nodes: Text[] = [];
    let current = walker.nextNode();

    while (current) {
        const text = current as Text;

        if (!isSentinelTextNode(text)) {
            nodes.push(text);
        }

        current = walker.nextNode();
    }

    return nodes;
}

export function getOffset(
    root: HTMLElement,
    targetNode: Node,
    targetOffset: number
): number {
    const result = getOffsetFromPosition(
        root,
        targetNode,
        targetOffset
    );

    return result ?? getTextLength(root);
}

export function getDomPosition(
    root: HTMLElement,
    offset: number
): DomPosition {
    const textNodes = getTextNodes(root);

    if (textNodes.length === 0) {
        return {
            node: root,
            offset: 0
        };
    }

    let currentOffset = 0;

    for (const node of textNodes) {
        const length = node.textContent?.length ?? 0;

        if (offset <= currentOffset + length) {
            return {
                node,
                offset: offset - currentOffset
            };
        }

        currentOffset += length;
    }

    const lastNode = textNodes[textNodes.length - 1];

    return {
        node: lastNode,
        offset: lastNode.textContent?.length ?? 0
    };
}

export function getSelectionRange(
    root: HTMLElement
): SelectionRange | null {
    const selection = window.getSelection();

    if (!selection || selection.rangeCount === 0) {
        return null;
    }

    const range = selection.getRangeAt(0);

    if (
        !root.contains(range.startContainer) ||
        !root.contains(range.endContainer)
    ) {
        return null;
    }

    const start = getOffset(
        root,
        range.startContainer,
        range.startOffset
    );

    const end = getOffset(
        root,
        range.endContainer,
        range.endOffset
    );

    return {
        start: Math.min(start, end),
        end: Math.max(start, end)
    };
}

export function setSelectionRange(
    root: HTMLElement,
    start: number,
    end: number
): boolean {
    const startPosition = getDomPosition(root, start);
    const endPosition = getDomPosition(root, end);

    const range = document.createRange();

    range.setStart(
        startPosition.node,
        startPosition.offset
    );

    range.setEnd(
        endPosition.node,
        endPosition.offset
    );

    const selection = window.getSelection();

    if (!selection) {
        return false;
    }

    selection.removeAllRanges();
    selection.addRange(range);

    return true;
}

export function getCaretClientRect(
    root: HTMLElement,
    offset: number
): DOMRect | null {
    const textLength = getTextLength(root);

    if (offset === textLength) {
        const sentinel = getSentinelTextNode(root);

        if (sentinel) {
            const sentinelRect = getTextNodeCaretRect(sentinel, 0);

            if (sentinelRect) {
                return sentinelRect;
            }
        }
    }

    const position = getDomPosition(root, offset);
    const range = document.createRange();

    range.setStart(position.node, position.offset);
    range.collapse(true);

    const rect = firstRect(range);

    if (rect) {
        return rect;
    }

    return getMarkerRect(root, range);
}

export function getCurrentCaretClientRect(
    root: HTMLElement
): DOMRect | null {
    const selection = getSelectionRange(root);

    if (!selection || selection.start !== selection.end) {
        return null;
    }

    return getCaretClientRect(root, selection.start);
}

export function isOffsetOnFirstVisualLine(
    root: HTMLElement,
    offset: number,
    tolerance = 3
): boolean {
    const current = getCaretClientRect(root, offset);
    const first = getCaretClientRect(root, 0);

    if (!current || !first) {
        return false;
    }

    return current.top <= first.top + tolerance;
}

export function isOffsetOnLastVisualLine(
    root: HTMLElement,
    offset: number,
    textLength: number,
    tolerance = 3
): boolean {
    const current = getCaretClientRect(root, offset);
    const last = getCaretClientRect(root, textLength);

    if (!current || !last) {
        return false;
    }

    return current.bottom >= last.bottom - tolerance;
}

export function getOffsetAtPoint(
    root: HTMLElement,
    x: number,
    y: number
): number {
    const nearestOffset = getNearestCaretOffset(root, x, y);

    if (nearestOffset !== null) {
        return nearestOffset;
    }

    const position = getDomPositionFromPoint(x, y);

    if (!position || !root.contains(position.node)) {
        return getNearestBoundaryOffset(root, y);
    }

    return getOffset(root, position.node, position.offset);
}

export function getWordRangeAtPoint(
    root: HTMLElement,
    x: number,
    y: number
): SelectionRange {
    const offset = getOffsetAtPoint(root, x, y);
    const text = getRootText(root);

    return getWordRange(text, offset);
}

export function getParagraphRangeAtPoint(
    root: HTMLElement,
    x: number,
    y: number
): SelectionRange {
    const offset = getOffsetAtPoint(root, x, y);
    const text = getRootText(root);

    return getParagraphRange(text, offset);
}

function getWordRange(text: string, offset: number): SelectionRange {
    if (text.length === 0) {
        return { start: 0, end: 0 };
    }

    const clampedOffset = Math.max(0, Math.min(offset, text.length));
    let index = clampedOffset;

    if (index === text.length || !isWordCharacter(text[index])) {
        index = Math.max(0, index - 1);
    }

    if (!isWordCharacter(text[index])) {
        return {
            start: clampedOffset,
            end: clampedOffset
        };
    }

    let start = index;
    let end = index + 1;

    while (start > 0 && isWordCharacter(text[start - 1])) {
        start--;
    }

    while (end < text.length && isWordCharacter(text[end])) {
        end++;
    }

    return { start, end };
}

function getParagraphRange(text: string, offset: number): SelectionRange {
    const clampedOffset = Math.max(0, Math.min(offset, text.length));
    let start = clampedOffset;
    let end = clampedOffset;

    while (start > 0 && text[start - 1] !== "\n") {
        start--;
    }

    while (end < text.length && text[end] !== "\n") {
        end++;
    }

    return { start, end };
}

function isWordCharacter(character: string | undefined): boolean {
    return character !== undefined && /[\p{L}\p{N}_]/u.test(character);
}

function getRootText(root: HTMLElement): string {
    return getTextNodes(root)
        .map(node => node.textContent ?? "")
        .join("");
}


function getNearestCaretOffset(
    root: HTMLElement,
    x: number,
    y: number
): number | null {
    const textLength = getTextLength(root);
    let best: {
        offset: number;
        verticalDistance: number;
        horizontalDistance: number;
    } | null = null;

    for (let offset = 0; offset <= textLength; offset++) {
        const rect = getCaretClientRect(root, offset);

        if (!rect) {
            continue;
        }

        const verticalDistance = getVerticalDistanceToRect(y, rect);
        const horizontalDistance = Math.abs(x - rect.left);

        if (
            !best ||
            verticalDistance < best.verticalDistance ||
            (
                verticalDistance === best.verticalDistance &&
                horizontalDistance < best.horizontalDistance
            )
        ) {
            best = {
                offset,
                verticalDistance,
                horizontalDistance
            };
        }
    }

    return best?.offset ?? null;
}

function getVerticalDistanceToRect(
    y: number,
    rect: DOMRect
): number {
    if (y >= rect.top && y <= rect.bottom) {
        return 0;
    }

    return Math.min(
        Math.abs(y - rect.top),
        Math.abs(y - rect.bottom)
    );
}

function getDomPositionFromPoint(
    x: number,
    y: number
): DomPosition | null {
    const doc = document as Document & {
        caretPositionFromPoint?: (x: number, y: number) => CaretPosition | null;
        caretRangeFromPoint?: (x: number, y: number) => Range | null;
    };

    if (doc.caretPositionFromPoint) {
        const position = doc.caretPositionFromPoint(x, y);

        if (position) {
            return {
                node: position.offsetNode,
                offset: position.offset
            };
        }
    }

    if (doc.caretRangeFromPoint) {
        const range = doc.caretRangeFromPoint(x, y);

        if (range) {
            return {
                node: range.startContainer,
                offset: range.startOffset
            };
        }
    }

    return null;
}

function getNearestBoundaryOffset(
    root: HTMLElement,
    y: number
): number {
    const rect = root.getBoundingClientRect();

    if (y <= rect.top) {
        return 0;
    }

    return getTextLength(root);
}


function getTextNodeCaretRect(
    node: Text,
    offset: number
): DOMRect | null {
    const range = document.createRange();

    range.setStart(node, offset);
    range.collapse(true);

    const rect = firstRect(range);

    if (rect) {
        return rect;
    }

    return node.parentElement?.getBoundingClientRect() ?? null;
}

function getSentinelTextNode(root: HTMLElement): Text | null {
    const sentinel = root.querySelector('[data-cobalt-sentinel="true"]');
    const node = sentinel?.firstChild;

    return node?.nodeType === Node.TEXT_NODE
        ? node as Text
        : null;
}

function firstRect(range: Range): DOMRect | null {
    const rects = Array.from(range.getClientRects());

    return rects.length > 0
        ? rects[0]
        : null;
}

function getMarkerRect(
    root: HTMLElement,
    range: Range
): DOMRect | null {
    const marker = document.createElement("span");

    marker.setAttribute("data-cobalt-caret-marker", "true");
    marker.textContent = "\u200B";

    range.insertNode(marker);

    const rect = marker.getBoundingClientRect();
    marker.remove();

    root.normalize();

    return rect.width === 0 && rect.height === 0
        ? null
        : rect;
}

function getOffsetFromPosition(
    root: Node,
    targetNode: Node,
    targetOffset: number
): number | null {
    let offset = 0;
    let found = false;

    function walk(node: Node): void {
        if (found) {
            return;
        }

        if (node === targetNode) {
            if (node.nodeType === Node.TEXT_NODE) {
                const text = node as Text;

                if (!isSentinelTextNode(text)) {
                    offset += Math.min(
                        targetOffset,
                        text.textContent?.length ?? 0
                    );
                }
            } else {
                for (let i = 0; i < targetOffset; i++) {
                    offset += getTextLength(node.childNodes[i]);
                }
            }

            found = true;
            return;
        }

        if (node.nodeType === Node.TEXT_NODE) {
            offset += getTextLength(node);
            return;
        }

        for (const child of Array.from(node.childNodes)) {
            walk(child);
        }
    }

    walk(root);

    return found
        ? offset
        : null;
}

function getTextLength(node: Node | undefined): number {
    if (!node) {
        return 0;
    }

    if (node.nodeType === Node.TEXT_NODE) {
        const text = node as Text;

        return isSentinelTextNode(text)
            ? 0
            : text.textContent?.length ?? 0;
    }

    let length = 0;

    for (const child of Array.from(node.childNodes)) {
        length += getTextLength(child);
    }

    return length;
}

function isSentinelTextNode(node: Text): boolean {
    return node.parentElement?.hasAttribute("data-cobalt-sentinel") ?? false;
}
